export declare const cherryThemeProviderTemplate = "\"use client\";\nimport React, { createContext, useEffect, useState } from \"react\";\nimport { ThemeProvider as StyledThemeProvider } from \"styled-components\";\nimport { Theme } from \"cherry-styled-components/src/lib\";\nimport { GlobalStyles } from \"@/components/layout/GlobalStyles\";\n\ninterface ThemeContextProps {\n  setTheme: any;\n}\n\nexport const ThemeContext = createContext<ThemeContextProps>({\n  setTheme: null,\n});\n\nfunction CherryThemeProvider({\n  children,\n  theme,\n  themeDark,\n}: {\n  children: React.ReactNode;\n  theme: Theme;\n  themeDark?: Theme;\n}) {\n  const [currentTheme, setTheme] = useState(theme);\n  useEffect(() => {\n    if (!themeDark) return setTheme(theme);\n    if (\n      localStorage.theme === \"dark\" ||\n      (!(\"theme\" in localStorage) &&\n        window.matchMedia(\"(prefers-color-scheme: dark)\").matches)\n    ) {\n      document.documentElement.classList.add(\"dark\");\n      setTheme(themeDark);\n    } else {\n      document.documentElement.classList.remove(\"dark\");\n      setTheme(theme);\n    }\n  }, []);\n  const GlobalStylesComponent = GlobalStyles(currentTheme);\n\n  return (\n    <StyledThemeProvider theme={currentTheme}>\n      <ThemeContext.Provider value={{ setTheme }}>\n        <GlobalStylesComponent />\n        {children}\n      </ThemeContext.Provider>\n    </StyledThemeProvider>\n  );\n}\n\nexport { CherryThemeProvider };";
